"use client";

import { useState } from "react";
import { useForm } from "react-hook-form";

export default function EmployeeForm({ initialData }) {
    console.log(initialData);
    

    const isEditMode = !!initialData;

    const [statusButton, setStatusButton]=useState(false);
    const [formData, setFormData] = useState({
        lastName: initialData?.lastName || "",
        firstName: initialData?.firstName || "",
        employeeCode: initialData?.employeeCode || "",
        email: initialData?.email || "",
        phone: initialData?.phone || "",
        gender: initialData?.gender || "",
        dateOfBirth: initialData?.dateOfBirth || "",
        startDate: initialData?.startDate || "",
        levelId: initialData?.levelId || "",
        address: initialData?.address || "",
        roleId: initialData?.roleId || "",
        documentUrl: initialData?.documentUrl || "",
        roleId: initialData?.roleId || "",
        documentUrl: initialData?.documentUrl || "",
        departmentId: initialData?.departmentId || "",
        status: initialData?.status??true,
    });
    const emailRegex = /^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$/;
    const phoneRegex = /^(03|05|07|08|09)[0-9]{8}$/;

    const handleChange = (e) => {
        let { name, value } = e.target;

    if (name == "status") {
        value = value === "true"; 
    }
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    

    const handleSubmit = (e) => {
        e.preventDefault();
        setStatusButton(true)
        if (isEditMode) {
            console.log("Gọi API Update với data:", formData);
        } else {
            console.log("Gọi API Create với data:", formData);
        }
    };

    return (
    <div className="bg-gray-100 min-h-screen">
        <div className="m-10 px-5 mx-auto max-w-6xl">
          <div className="flex items-center gap-5 pb-3">
              <i className="fa-solid fa-arrow-left"></i> <div className="text-base">Thêm mới nhân viên</div>
          </div>
          <form action="" onSubmit={handleSubmit}>
          <div className="grid grid-cols-7 gap-5">
            
              <div className="col-span-5">
                <div className="bg-white p-7 rounded-xl">
                <h2 className="text-lg font-semibold mb-4">Hồ sơ nhân viên</h2>

                <div className="flex items-center gap-4 mb-6">
                  <div className="w-16 h-16 bg-gray-400 rounded-full flex items-center justify-center overflow-hidden">
                      <svg className="w-10 h-10 text-gray-200" fill="currentColor" viewBox="0 0 24 24">
                        <path d="M24 20.993V24H0v-2.996A14.977 14.977 0 0112.004 15c4.904 0 9.26 2.354 11.996 5.993zM16.002 8.999a4 4 0 11-8 0 4 4 0 018 0z" />
                      </svg>
                  </div>
                    <input type="file" id="avatar-upload" placeholder="Tải ảnh lên" className="hidden"/>
                    <label htmlFor="avatar-upload" className="px-4 py-2 border border-gray-300 rounded-lg text-sm font-medium hover:bg-gray-50 cursor-pointer inline-block">
                                Tải ảnh lên
                            </label>
                </div>
                
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label htmlFor="" className="tex-sm text-gray-600 mb-1">Họ và tên đệm</label>
                    <input type="text" value={formData.firstName} onChange={handleChange} name="firstName" className="w-full border border-gray-300 rounded-lg px-3 py-1.5 " />
                    <span className="text-red-500">{statusButton&&formData.firstName==""?"bạn chưa nhập họ tên đệm":""}</span>
                  </div>
                   
                  <div>
                    <label htmlFor="" className="tex-sm text-gray-600 mb-1">Tên</label>
                    <input type="text" value={formData.lastName} onChange={handleChange} name="lastName" className="w-full border border-gray-300 rounded-lg px-3 py-1.5 " />
                    <span className="text-red-500">{statusButton&&formData.lastName==""?"bạn chưa nhập tên":""}</span>
                  </div>
                  <div>
                    <label htmlFor="" className="tex-sm text-gray-600 mb-1">Ngày sinh</label>
                    <input type="date" value={formData.dateOfBirth} onChange={handleChange} name="dateOfBirth" className="w-full border border-gray-300 rounded-lg px-3 py-1.5 text-gray-600" />
                    <span className="text-red-500">{statusButton&&formData.dateOfBirth==""?"bạn chưa nhập ngày sinh":""}</span>
                  </div>
                  <div>
                    <label htmlFor="" className="tex-sm text-gray-600 mb-1">Giới tính</label>
                      <select value={formData.gender} onChange={handleChange} name="gender" className="w-full border border-gray-300 rounded-lg px-3 py-1.5 appearance-none focus:outline-none focus:ring-1 focus:ring-blue-500 bg-white text-gray-800">
                          <option className="text-gray-600" value={"Nam"}>Nam</option>
                          <option className="text-gray-600" value={"Nữ"}>Nữ</option>
                      </select>
                      <span className="text-red-500">{statusButton&&formData.gender==""?"bạn chưa nhập giới tính":""}</span>
                  </div>
                  <div>
                    <label htmlFor="" className="tex-sm text-gray-600 mb-1">Ngày bắt đầu làm việc</label>
                    <input type="date" value={formData.startDate} onChange={handleChange} name="startDate" className="w-full border border-gray-300 rounded-lg px-3 py-1.5 " />
                    <span className="text-red-500">{statusButton&&formData.startDate==""?"bạn chưa nhập ngày bắt đầu làm việc":""}</span>
                  </div>
                  <div>
                    <label htmlFor="" className="tex-sm text-gray-600 mb-1">Mã nhân viên</label>
                    <input type="text" value={formData.employeeCode} onChange={handleChange} name="employeeCode" className="w-full border border-gray-300 rounded-lg px-3 py-1.5 " />
                    <span className="text-red-500">{statusButton&&formData.employeeCode==""?"bạn chưa nhập mã nhân viên":""}</span>
                  </div>
                  <div>
                    <label htmlFor="" className="tex-sm text-gray-600 mb-1">Thuộc cấp</label>
                    <select value={formData.levelId} onChange={handleChange} name="levelId" className="w-full border border-gray-300 rounded-lg px-3 py-2 ">
                      <option>Vui lòng chọn</option>
                      {levels.map(item=>(
                        <option key={item.id} value={item.id}>{item.name}</option>
                      ))}
                    </select>
                    <span className="text-red-500">{statusButton&&formData.levelId==""?"bạn chưa nhập thuộc cấp":""}</span>
                  </div>
                  <div>
                    <label htmlFor="" className="tex-sm text-gray-600 mb-1">Số điện thoại</label>
                    <input type="text" value={formData.phone} onChange={handleChange} name="phone" className="w-full border border-gray-300 rounded-lg px-3 py-1.5 " />
                    <span className="text-red-500">{statusButton&&formData.phone==""?"bạn chưa nhập số điện thoại": statusButton && !phoneRegex.test(formData.phone)
                          ? "số điẹn thoại không đúng định dạng"
                          : ""}</span>
                  </div>

                  <div className="md:col-span-2">
                    <label htmlFor="" className="tex-sm text-gray-600 mb-1">Địa chỉ</label>
                    <input type="text" value={formData.address} onChange={handleChange} name="address" className="w-full border border-gray-300 rounded-lg px-3 py-1.5 " />
                    <span className="text-red-500">{statusButton&&formData.address==""?"bạn chưa nhập địa chỉ":""}</span>
                  </div>
                  <div className="md:col-span-2">
                    <label htmlFor="" className="tex-sm text-gray-600 mb-1">Phòng ban</label>
                    <select value={formData.departmentId} onChange={handleChange} name="departmentId" className="w-full border border-gray-300 rounded-lg px-3 py-2 ">
                      <option>Vui lòng chọn</option>
                      {departments.map(item=>(
                        <option key={item.id} value={item.id}>{item.name}</option>
                      ))}
                      
                    </select>
                    <span className="text-red-500">{statusButton&&formData.departmentId==""?"bạn chưa nhập phòng ban":""}</span>
                  </div>
                </div>
                </div>
                <div className="bg-white p-7 rounded-xl my-8">
                  <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
                    <h2 className="text-lg font-semibold mb-4">Giấy tờ đính kèm</h2>
                    <label className="block text-sm text-gray-600 mb-2">Tải bản scan giấy tờ</label>
                    
                    <div className="relative border-2 border-dashed border-gray-200 rounded-xl p-8 flex flex-col items-center justify-center text-center bg-gray-100 hover:bg-gray-50 ">
                        <input type="file" onChange={handleChange} name="documentUrl" className="absolute w-full h-full opacity-0 " />
                        <span className="px-4 py-2 border border-gray-300 rounded-lg bg-white text-sm font-medium text-gray-700 mb-2 shadow-sm ">
                            Tải lên
                        </span>
                        <p className="text-xs text-gray-400 pointer-events-none">PDF, JPG, JPEG, PNG</p>
                    </div>
                    <div className={!isEditMode?"hidden":"mt-2 text-sm text-gray-600"}>
                        Giấy tờ hiện tại: <a href={formData.documentUrl} target="_blank" rel="noreferrer" className="text-blue-600 underline">Xem file</a>
                    </div>
                  </div>
                </div>
              </div>


              <div className="col-span-2">
                <div className={!isEditMode?"hidden":"bg-white p-7 rounded-xl mb-5"}>
                  <h2 className="text-base font-semibold mb-4">Trang thái làm việc</h2>
                  <div>
                      <select value={String(formData.status)} onChange={handleChange} name="status" className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:outline-none focus:ring-1 focus:ring-blue-500 bg-white text-gray-500">
                          <option value="true">Đang làm việc</option>
                          <option value="false">nghỉ việc</option>
                      </select>
                    </div>
                </div>
                <div className="bg-white p-7 rounded-xl mb-5">
                  <h2 className="text-base font-semibold mb-4">Tài khoản đăng nhập SSO</h2>
                  <div>
                      <label className="block text-sm text-gray-600 mb-1">Email</label>
                      <input value={formData.email} onChange={handleChange} name="email" type="email" className="w-full border border-gray-300 rounded-lg px-3 py-1.5 focus:outline-none focus:ring-1 focus:ring-blue-500 text-gray-700"/>
                      <span className="text-red-500">{statusButton && formData.email === ""
                          ? "Bạn chưa nhập email"
                          : statusButton && !emailRegex.test(formData.email)
                          ? "Email không đúng định dạng"
                          : ""}
                    </span>
                    </div>
                </div>
                <div className="bg-white p-7 rounded-xl mb-5">
                  <h2 className="text-base font-semibold mb-4">Vai trò khác</h2>
                  <div>
                      <label className="block text-sm text-gray-600 mb-1">Vai trò</label>
                      
                      <select value={formData.roleId} onChange={handleChange} name="roleId" className="w-full border border-gray-300 rounded-lg px-3 py-2 focus:outline-none focus:ring-1 focus:ring-blue-500 bg-white text-gray-500">
                          <option value="">Vui lòng chọn</option>
                          {roles.map(item=>(
                        <option key={item.id} value={item.id}>{item.name}</option>
                      ))}
                      </select>
                      <span className="text-red-500">{statusButton&&formData.roleId==""?"bạn chưa nhập vai trò":""}</span>
                    </div>
                </div>
              </div>
                
          </div>
          <button type="submit" className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700">
                    {isEditMode ? "Lưu thay đổi" : "Tạo mới"}
                </button>
              </form>
        </div>
    </div>
  )
}